class TrieNode:
    def __init__(self):
        self.children = {}
        self.isLeaf = False

def insert(words):
    root = TrieNode()
    for word in words:
        for c in word:
            if c not in root.children: root.children[c] = TrieNode()
            else: root = root.children[c]
        root.isLeaf = True
    return True


