function insert(words) {
    var root = {
        children: {},
        isLeaf: false
    }
    for (var word in words) {
        for (var c in word) {
            if (words[word].charAt(c) in root.children) root = root.children[words[word].charAt(c)]
            else root.children[words[word].charAt(c)] = {
                children: {},
                isLeaf: false
            }
        }
        root.isLeaf = true;
    }
    return true;
}

